import "./orderList.css";
import { DataGrid } from "@material-ui/data-grid";
import { Slider } from "@material-ui/core";
import { useDispatch, useSelector } from 'react-redux';
import { useEffect, useState } from "react";
import { getOrders, deleteOrder } from "../../redux/apiCalls";
import { Link } from "react-router-dom";
import { DeleteOutline } from "@material-ui/icons";
import {format} from 'timeago.js';


const OrderList = () => {
    const dispatch = useDispatch();
    const orders = useSelector(state => state.order.orders);
    const [rowHeight, setRowHeight] = useState(50);

    useEffect(() => {
        getOrders(dispatch)
    }, [dispatch]);

    const handleDelete = (id) => {
        deleteOrder(id, dispatch)
    };

    const handleRowHeightChange = (e, newValue) => {
        setRowHeight(newValue)
    }

  const columns = [
    { field: "_id", headerName: "ID", width: 200 },
    {
      field: "userId",
      headerName: "User",
      width: 200,
      renderCell: (params) => {
        return (
          <div className="orderListOrder">
            {/* <img className="userListImg" src={params.row.avatar} alt="" /> */}
            {params.row.userId}
          </div>
        );
      },
    },
    { field: "email", headerName: "Email", width: 200 },
    {
      field: "status",
      headerName: "Status",
      width: 120,
    },
    {
        field: "products",
        headerName: "Products",
        width: 200,
        renderCell: (params) => {
            console.log(params.row.products)
            return (
                <div className="productCell">
                    {params.row.products.map(product => (
                        <div key={product._id}>
                            {product.title}
                        </div>
                    ))}
                </div>
            );
        }
    },
    {
      field: "createdAt",
      headerName: "Created At",
      width: 160,
      renderCell: (params) => {
        return (
            <div>
                {format(params.row.createdAt)}
            </div>
        )
      }
    },
    {
      field: "action",
      headerName: "Action",
      width: 150,
      renderCell: (params) => {
        return (
          <>
            <Link to={"/order/" + params.row._id}>
              <button className="orderListEdit">Edit</button>
            </Link>
            <DeleteOutline
              className="orderListDelete"
              onClick={() => handleDelete(params.row._id)}
            />
          </>
        );
      },
    },
  ];

  return (
    <div className="orderList">
        <Slider
            value={rowHeight}
            min={50}
            max={150}
            step={10}
            onChange={handleRowHeightChange}
            aria-labelledby="row-height-slider"
        />
      <DataGrid
        rows={orders}
        disableSelectionOnClick
        columns={columns}
        getRowId={(row) => row._id}
        pageSize={8}
        checkboxSelection
        rowHeight={100}
        // getRowHeight={(params) => {
        //     if (params.field === "products") {
        //         const productHeight = 25;
        //         const padding = 16;
        //         return (
        //             (params.row.products.length * 25) + rowHeight + 
        //             (padding * 2) + 
        //             (rowHeight - 20)
        //         );
        //     }
        //     return rowHeight;
        // }}
      />
    </div>
  )
}

export default OrderList;
